section.programlisting:
-- Install (requires postgis to be installed first)
CREATE EXTENSION postgis_ecef_eci;

-- Upgrade to latest version
ALTER EXTENSION postgis_ecef_eci UPDATE;

-- Remove (CASCADE drops dependent objects)
DROP EXTENSION postgis_ecef_eci CASCADE;

refsection.programlisting:
-- A satellite position in ECEF (SRID 4978), metres
SELECT ST_AsText(
    ST_ECEF_To_ECI(
        ST_SetSRID(ST_MakePoint(6378137, 0, 0), 4978),
        '2024-06-15 12:00:00+00'::timestamptz
    )
);

SELECT ST_SRID(eci_geom), ST_AsText(eci_geom)
FROM (
    SELECT ST_ECEF_To_ECI(
        ST_SetSRID(ST_MakePoint(6378137, 0, 0), 4978),
        '2024-06-15 12:00:00+00'::timestamptz,
        'TEME'
    ) AS eci_geom
) sub;
-- SRID of result is 900003 (TEME)

SELECT ST_AsText(
    ST_ECI_To_ECEF(
        ST_SetSRID(ST_MakePoint(6000000, 2000000, 1000000), 900001),
        '2024-06-15 12:00:00+00'::timestamptz,
        'ICRF'
    )
);
-- Result SRID is 4978 (ECEF)

-- Table of satellite positions in ECEF
CREATE TABLE sat_positions (
    id serial PRIMARY KEY,
    geom geometry(PointZ, 4978)
);

-- Expression index: find satellites by ECEF X range
CREATE INDEX idx_sat_ecef_x ON sat_positions (ST_ECEF_X(geom));

-- Query using the index
SELECT id FROM sat_positions
WHERE ST_ECEF_X(geom) BETWEEN 6000000 AND 7000000;

CREATE TABLE ecef_objects (
    id serial PRIMARY KEY,
    geom geometry(PointZ, 4978),
    x_m float8 GENERATED ALWAYS AS (ST_ECEF_X(geom)) STORED,
    y_m float8 GENERATED ALWAYS AS (ST_ECEF_Y(geom)) STORED,
    z_m float8 GENERATED ALWAYS AS (ST_ECEF_Z(geom)) STORED
);

INSERT INTO ecef_objects (geom)
VALUES (ST_SetSRID(ST_MakePoint(6378137, 0, 0), 4978));

SELECT id, x_m, y_m, z_m FROM ecef_objects;
-- id | x_m     | y_m | z_m
-- 1  | 6378137 | 0   | 0

SELECT CASE
    WHEN EXISTS (
        SELECT 1 FROM postgis_eop_interpolate('2024-06-15 00:00:00+00')
    ) THEN 'EOP data available'
    ELSE 'EOP data not loaded for this date'
END AS status;

-- Example pg_cron job (requires pg_cron extension)
-- Downloads IERS Bulletin A weekly and loads it
SELECT cron.schedule(
    'refresh-eop',
    '0 3 * * 1',  -- every Monday at 03:00 UTC
    $$
    COPY (SELECT '') TO PROGRAM
        'curl -sS https://datacenter.iers.org/data/latestVersion/finals2000A.data -o /tmp/finals2000A.data';
    SELECT postgis_eop_load(pg_read_file('/tmp/finals2000A.data'));
    $$
);

CALL postgis_refresh_eop();
-- NOTICE: postgis_refresh_eop: placeholder -- configure an external scheduler
--         to fetch IERS Bulletin A data and call postgis_eop_load()
